package com.hospital.management.model;
/** Safe create/edit input; password values are never included in toString. */
public class DoctorForm{private Long doctorId,departmentId;private String username,email,password,confirmPassword,registrationNumber,firstName,lastName,specialization,qualification,phone,consultationFee,status;
 public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getUsername(){return username;}public void setUsername(String v){username=v;}public String getEmail(){return email;}public void setEmail(String v){email=v;}public String getPassword(){return password;}public void setPassword(String v){password=v;}public String getConfirmPassword(){return confirmPassword;}public void setConfirmPassword(String v){confirmPassword=v;}public String getRegistrationNumber(){return registrationNumber;}public void setRegistrationNumber(String v){registrationNumber=v;}public String getFirstName(){return firstName;}public void setFirstName(String v){firstName=v;}public String getLastName(){return lastName;}public void setLastName(String v){lastName=v;}public String getSpecialization(){return specialization;}public void setSpecialization(String v){specialization=v;}public String getQualification(){return qualification;}public void setQualification(String v){qualification=v;}public String getPhone(){return phone;}public void setPhone(String v){phone=v;}public String getConsultationFee(){return consultationFee;}public void setConsultationFee(String v){consultationFee=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public String toString(){return"DoctorForm{id="+doctorId+", username='"+username+"', registration='"+registrationNumber+"'}";}}
